export async function run(ctx, params) {
  const itemName = params.itemName;
  const tablePos = params.tablePosition;

  // Verify proximity to the specific crafting table intended for diagnosis
  const pos = await ctx.position();
  const dx = pos.x - tablePos.x;
  const dy = pos.y - tablePos.y;
  const dz = pos.z - tablePos.z;
  const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);

  if (dist > 4.5) {
    return {
      status: 'failed',
      reason: 'too_far_from_target_table',
      distance: dist,
      message: `Actor is ${dist.toFixed(2)} blocks from target table at (${tablePos.x},${tablePos.y},${tablePos.z}); must be within 4.5 blocks for reliable interaction.`
    };
  }

  try {
    // Deliberate diagnostic probe: attempt table craft with an item that is normally inventory-grid.
    // We expect this to potentially fail, but the *type* of failure is the evidence we need.
    const result = await ctx.craftWithTable(itemName);
    return {
      status: 'success',
      diagnostic: 'table_craft_accepted_stick',
      result: result,
      message: `craftWithTable('${itemName}') succeeded unexpectedly. Table station is functional and accepted stick recipe.`
    };
  } catch (err: any) {
    const errMsg = err?.message || String(err);
    return {
      status: 'diagnostic_complete',
      diagnostic: 'table_craft_rejected_stick',
      error: errMsg,
      message: `craftWithTable('${itemName}') failed as expected. Error distinguishes station functionality from recipe validity.`
    };
  }
}

export async function run(ctx, params) {
  const startedAt = Date.now();
  const out = {
    status: "blocked",
    live: false,
    blocker: null,
    evidence: {}
  };

  try {
    const pos = await ctx.position();
    const items = await ctx.inventoryItems();

    out.live = true;
    out.status = "ok";
    out.evidence.position = { x: pos.x, y: pos.y, z: pos.z };
    out.evidence.inventory = items.map((it) => ({ name: it.name, count: it.count }));

    try {
      await ctx.say("npc_b runtime live; ready to resume spawn-side prerequisite work.");
      out.evidence.say = "sent";
    } catch (sayErr) {
      out.evidence.say = { error: String((sayErr && sayErr.message) || sayErr) };
    }

    await ctx.wait({ durationMs: 250 });
    out.evidence.elapsedMs = Date.now() - startedAt;
    return out;
  } catch (err) {
    out.blocker = String((err && err.message) || err);
    out.evidence.elapsedMs = Date.now() - startedAt;
    return out;
  }
}

export async function run(ctx, params) {
  const result = {
    status: 'blocked',
    phase: 'start',
    attempts: []
  };

  const note = (entry) => {
    result.attempts.push(entry);
  };

  const summarizeError = (err) => {
    if (!err) return 'unknown_error';
    if (typeof err === 'string') return err;
    if (err && typeof err.message === 'string' && err.message.length > 0) return err.message;
    try {
      return JSON.stringify(err);
    } catch {
      return String(err);
    }
  };

  try {
    const obs = await ctx.observe();
    note({ phase: 'initial_observe', ok: true, observation: obs });
    return {
      status: 'connected',
      phase: 'initial_observe',
      attempts: result.attempts,
      evidence: 'observe completed without throwing'
    };
  } catch (err1) {
    note({ phase: 'initial_observe', ok: false, error: summarizeError(err1) });
  }

  try {
    await ctx.wait({ durationMs: 1200 });
    note({ phase: 'wait', ok: true, durationMs: 1200 });
  } catch (err2) {
    note({ phase: 'wait', ok: false, error: summarizeError(err2) });
  }

  try {
    const obs2 = await ctx.observe();
    note({ phase: 'post_wait_observe', ok: true, observation: obs2 });
    return {
      status: 'connected_after_wait',
      phase: 'post_wait_observe',
      attempts: result.attempts,
      evidence: 'observe completed after a bounded wait'
    };
  } catch (err3) {
    note({ phase: 'post_wait_observe', ok: false, error: summarizeError(err3) });
  }

  try {
    await ctx.say('runtime reconnect probe recorded: still blocked');
    note({ phase: 'say', ok: true });
  } catch (err4) {
    note({ phase: 'say', ok: false, error: summarizeError(err4) });
  }

  return {
    status: 'blocked',
    phase: 'final',
    reason: 'runtime remained disconnected_or_error after bounded probe',
    attempts: result.attempts
  };
}

export async function run(ctx, params) {
  const startedAt = Date.now();
  const waitMs = 1200;

  try {
    await ctx.wait({ durationMs: waitMs });

    const observed = await ctx.observe({});
    const position = await ctx.position();

    return {
      status: 'completed',
      live: true,
      waitedMs: waitMs,
      position,
      observed
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return {
      status: 'blocked',
      live: false,
      waitedMs: waitMs,
      elapsedMs: Date.now() - startedAt,
      blocker: 'runtime_unavailable_or_disconnected',
      message
    };
  }
}

export async function run(ctx, params) {
  void params;
  const startedAt = Date.now();
  const result = {
    skill: "probeRuntimeReadiness",
    status: "started",
  };

  try {
    await ctx.say("[probeRuntimeReadiness] live-check");
    result.say = "sent";
    result.status = "live";
  } catch (err) {
    result.status = "blocked";
    result.blocker = "say_failed";
    result.error = String(err && err.message ? err.message : err);
    result.elapsedMs = Date.now() - startedAt;
    return result;
  }

  try {
    const pos = await ctx.position();
    result.position = pos;
  } catch (err) {
    result.position_error = String(err && err.message ? err.message : err);
  }

  try {
    const inv = await ctx.inventoryItems();
    result.inventory = Array.isArray(inv)
      ? inv.map((item) => ({ name: item && item.name, count: item && item.count })).slice(0, 16)
      : inv;
  } catch (err) {
    result.inventory_error = String(err && err.message ? err.message : err);
  }

  try {
    const obs = await ctx.observe();
    result.observe = obs;
  } catch (err) {
    result.observe_error = String(err && err.message ? err.message : err);
  }

  result.elapsedMs = Date.now() - startedAt;
  return result;
}

export async function run(ctx, params) {
  const startedAt = Date.now();
  const out = {
    status: 'unknown',
    live: false,
    checked: [],
    evidence: {},
    error: null,
    elapsedMs: 0,
  };

  const noteError = (err) => {
    if (err == null) return 'unknown_error';
    if (typeof err === 'string') return err;
    if (typeof err === 'object' && 'message' in err && typeof err.message === 'string') return err.message;
    try {
      return JSON.stringify(err);
    } catch {
      return String(err);
    }
  };

  try {
    const pos = await ctx.position();
    out.live = true;
    out.checked.push('position');
    out.evidence.position = pos || null;
  } catch (err) {
    const msg = noteError(err);
    out.error = msg;
    out.elapsedMs = Date.now() - startedAt;
    if (/disconnected|ended|socketClosed|not connected|client/i.test(msg)) {
      out.status = 'disconnected_or_error';
    } else {
      out.status = 'blocked_or_error';
    }
    return out;
  }

  try {
    const items = await ctx.inventoryItems();
    out.checked.push('inventoryItems');
    out.evidence.inventoryItems = Array.isArray(items)
      ? items.map((item) => ({ name: item.name, count: item.count }))
      : items;
  } catch (err) {
    const msg = noteError(err);
    out.error = out.error || msg;
    if (/disconnected|ended|socketClosed|not connected|client/i.test(msg)) {
      out.status = 'disconnected_or_error';
      out.elapsedMs = Date.now() - startedAt;
      return out;
    }
  }

  try {
    const scan = await ctx.observe({});
    out.checked.push('observe');
    out.evidence.observe = scan || null;
    out.status = 'live_observed';
  } catch (err) {
    const msg = noteError(err);
    out.error = out.error || msg;
    if (/disconnected|ended|socketClosed|not connected|client/i.test(msg)) {
      out.status = 'live_but_observe_blocked_disconnect';
    } else {
      out.status = 'live_but_observe_failed';
    }
  }

  out.elapsedMs = Date.now() - startedAt;
  return out;
}

export async function run(ctx, params) {
  const startedAt = Date.now();
  const result = {
    status: 'blocked',
    phase: 'probe',
    live: false,
    probe: 'runtime_recovery_and_nearby_observe',
    evidence: [],
    recommendation: null,
    blocker: null,
  };

  try {
    await ctx.wait({ durationMs: 200 });
  } catch (err) {
    result.blocker = `wait_failed:${String(err && err.message ? err.message : err)}`;
    return result;
  }

  try {
    const pos = await ctx.position();
    result.evidence.push({ kind: 'position', value: pos });
    result.live = true;
  } catch (err) {
    result.blocker = `mineflayer_client_disconnected_or_ended:${String(err && err.message ? err.message : err)}`;
    return result;
  }

  try {
    const obs = await ctx.observe();
    result.evidence.push({ kind: 'observe', value: obs });
    result.status = 'live';
    result.phase = 'observed';

    const blocks = [];
    const nearbyBlocks = obs && typeof obs === 'object'
      ? (Array.isArray(obs.nearby_blocks) ? obs.nearby_blocks : Array.isArray(obs.nearbyBlocks) ? obs.nearbyBlocks : [])
      : [];

    for (const entry of nearbyBlocks) {
      if (entry && typeof entry === 'object' && typeof entry.name === 'string') {
        blocks.push(entry.name);
      }
    }

    if (blocks.includes('stone')) {
      result.recommendation = 'smallest_safe_prerequisite: mine_cobblestone_or_stone';
    } else if (blocks.includes('crafting_table')) {
      result.recommendation = 'smallest_safe_prerequisite: use_nearby_crafting_table_for_next_tool_recipe';
    } else if (blocks.includes('water')) {
      result.recommendation = 'smallest_safe_prerequisite: reassess_safe_survival_movement_near_water_and_stone';
    } else {
      result.recommendation = 'smallest_safe_prerequisite: inspect_loaded_nearby_blocks_for_stone_or_other_basic_material';
    }

    result.elapsedMs = Date.now() - startedAt;
    return result;
  } catch (err) {
    result.phase = 'observe_failed';
    result.blocker = `observe_failed:${String(err && err.message ? err.message : err)}`;
    result.elapsedMs = Date.now() - startedAt;
    return result;
  }
}

export async function run(ctx, params) {
  const startedAt = Date.now();
  const maxWaitMs = 250;

  try {
    await ctx.wait({ durationMs: maxWaitMs });

    const observation = await ctx.observe();
    const position = await ctx.position();
    const inventory = await ctx.inventoryItems();

    return {
      status: "ok",
      live: true,
      elapsedMs: Date.now() - startedAt,
      position,
      inventory,
      observation
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return {
      status: "blocked",
      live: false,
      elapsedMs: Date.now() - startedAt,
      blocker: "mineflayer_client_disconnected_or_ended",
      error: message
    };
  }
}
